class Solution:
    def subarraysWithKDistinct(self, nums, k):
        n = len(nums)
        count = 0
        for i in range(n):
            seen = set()
            for j in range(i, n):
                seen.add(nums[j])
                if len(seen) == k:
                    count += 1
                elif len(seen) > k:
                    break
        return count

