class Solution:
    def subarraysWithKDistinct(self, nums, k):
        def at_most(m):
            if m < 0:
                return 0
            from collections import defaultdict
            cnt = defaultdict(int)
            left = 0
            distinct = 0
            total = 0
            for right, v in enumerate(nums):
                if cnt[v] == 0:
                    distinct += 1
                cnt[v] += 1
                while distinct > m:
                    cnt[nums[left]] -= 1
                    if cnt[nums[left]] == 0:
                        distinct -= 1
                    left += 1
                total += right - left + 1
            return total
        return at_most(k) - at_most(k - 1)

