var subarraysWithKDistinct = function(nums, k) {
    const atMost = (m) => {
        if (m < 0) return 0;
        const cnt = new Map();
        let left = 0, distinct = 0, total = 0;
        for (let right = 0; right < nums.length; right++) {
            const v = nums[right];
            if ((cnt.get(v) || 0) === 0) distinct++;
            cnt.set(v, (cnt.get(v) || 0) + 1);
            while (distinct > m) {
                const lv = nums[left];
                cnt.set(lv, cnt.get(lv) - 1);
                if (cnt.get(lv) === 0) distinct--;
                left++;
            }
            total += right - left + 1;
        }
        return total;
    };
    return atMost(k) - atMost(k - 1);
};
